import 'dart:convert'; import 'package:web_socket_channel/web_socket_channel.dart'; import '../config.dart'; typedef WsCallback = void Function(Map<String, dynamic> data); class WsService { static WebSocketChannel? _channel; static final Map<String, List<WsCallback>> _listeners = {}; static void connect(String role, WsCallback onMessage) { _listeners[role] = _listeners[role] ?? []; _listeners[role]!.add(onMessage); _channel = WebSocketChannel.connect(Uri.parse("\${AppConfig.wsUrl}/ws/\$role")); _channel!.stream.listen((data) { final msg = jsonDecode(data); _listeners[role]?.forEach((cb) => cb(msg)); }); } static void send(String role, Map<String, dynamic> data) { _channel?.sink.add(jsonEncode(data)); } static void close() => _channel?.sink.close(); }
